#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PublicFieldDefinitionOptionalityMarkerEnum {
    Question,
    Bang,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for PublicFieldDefinitionOptionalityMarkerEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let kind_id: u16 = u16::from_napi_value(env, napi_val)?;
        match kind_id {
            132 => Ok(Self::Question), // "?"
            17 => Ok(Self::Bang), // "!"
            other => Err(::napi::Error::from_reason(format!(
                "unknown kind id {{other}} for PublicFieldDefinitionOptionalityMarkerEnum",
            ))),
        }
    }
}

#[cfg(feature = "napi-bindings")]
