#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum UnaryExpressionOperatorEnum {
    Bang,
    Tilde,
    Minus,
    Plus,
    TypeofKw,
    VoidKw,
    DeleteKw,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for UnaryExpressionOperatorEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let kind_id: u16 = u16::from_napi_value(env, napi_val)?;
        match kind_id {
            17 => Ok(Self::Bang), // "!"
            91 => Ok(Self::Tilde), // "~"
            77 => Ok(Self::Minus), // "-"
            76 => Ok(Self::Plus), // "+"
            9 => Ok(Self::TypeofKw), // "typeof"
            92 => Ok(Self::VoidKw), // "void"
            93 => Ok(Self::DeleteKw), // "delete"
            other => Err(::napi::Error::from_reason(format!(
                "unknown kind id {{other}} for UnaryExpressionOperatorEnum",
            ))),
        }
    }
}

